css:
.ps-wiki-article-header { padding-block-end: var(--pds-space-2); border-block-end: 1px solid var(--pds-border-subtle); }
.ps-wiki-article-header__breadcrumb ol { list-style: none; padding: 0; display: flex; gap: 0.25em; font-size: 0.875rem; color: var(--pds-text-secondary); }
.ps-wiki-article-header__title-row { display: flex; align-items: flex-start; gap: var(--pds-space-1); margin-block: var(--pds-space-1); }
.ps-wiki-article-header__title { font-family: var(--pds-font-heading); font-size: var(--pds-font-size-10); font-weight: 700; line-height: 1.2; color: var(--pds-text-primary); margin: 0; }
.ps-wiki-article-header__meta { display: flex; flex-wrap: wrap; gap: 0.25em; font-size: 0.875rem; color: var(--pds-text-secondary); }
.ps-wiki-article-header__divider { margin-inline: 0.2em; }
.ps-wiki-article-header__history { color: var(--pds-link); }
